SELECT u.id, u.user_name, u.password, u.email, u.mobile, u.nick_name, u.gender, u.status, u.dept_id, d.dept_name, DATE_FORMAT(u.create_time, '%Y-%m-%d %H:%i:%s') AS create_time FROM sys_user u LEFT JOIN department d ON u.dept_id = d.dept_id
AND ( u.user_name LIKE CONCAT('%', #{keywords}, '%') OR u.nick_name LIKE CONCAT('%' #{keywords}, '%') OR u.mobile = #{keywords} )
AND u.status = #{status}
AND u.dept_id = #{deptId}
AND DATE(u.create_time) BETWEEN #{startTime} AND #{endTime}
ORDER BY u.create_time DESC

SELECT id, user_name, password
FROM sys_user


       AND user_name = #{userName}

